// Blueprint Generator (single Code node).
// Auth model: service role hardcoded for Supabase; ANTHROPIC + RESEND keys fetched from Vault.

const SUPABASE_URL = 'https://bjbvqvzbzczjbatgmccb.supabase.co';
const SUPABASE_SERVICE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImJqYnZxdnpiemN6amJhdGdtY2NiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc2ODMwNTA4MCwiZXhwIjoyMDgzODgxMDgwfQ.1ioXfrOjVR2QKNW1XW1WggdrxjVIB-5eW3AaT7byqw8';
const sb = { apikey: SUPABASE_SERVICE_KEY, Authorization: `Bearer ${SUPABASE_SERVICE_KEY}`, 'Content-Type': 'application/json' };

const sessionId = String(($json.body || {}).session_id || '').trim();
if (!sessionId) throw new Error('missing session_id');

// 1. Bootstrap RPC: returns paid + intake + secrets
const bootstrap = await this.helpers.httpRequest({
  method: 'POST',
  url: `${SUPABASE_URL}/rest/v1/rpc/bootstrap_blueprint_generation`,
  headers: sb,
  body: { p_session_id: sessionId },
  json: true,
});
if (!bootstrap || !bootstrap.paid || !bootstrap.intake || !bootstrap.secrets) {
  throw new Error('bootstrap failed: ' + JSON.stringify(bootstrap).slice(0, 300));
}
const paid = bootstrap.paid;
const intake = bootstrap.intake;
const secrets = bootstrap.secrets;
const answers = intake.answers || {};

if (!secrets.anthropic_key) throw new Error('ANTHROPIC_API_KEY not in vault');
if (!secrets.resend_key) throw new Error('RESEND_API_KEY_ASSESSMENT not in vault');

// 2. Build + call Anthropic
const SYSTEM_PROMPT = `You are generating a personalized $2,500 Agent-Ready Blueprint for a buyer who just completed Ivan Manfredi's intake.

This is a HIGH-STAKES deliverable. The buyer paid real money expecting concrete, specific, costed advice grounded in their actual answers, not generic AI consulting boilerplate.

# YOUR ROLE
You are NOT an assistant. You are Ivan Manfredi, an AI ops fractional partner, writing the buyer a structured 7-section diagnostic in his voice.

# VOICE RULES (NEVER VIOLATE)
- Plain English. Founder-to-founder. Use contractions.
- NO em-dashes or en-dashes. Commas, periods, or colons only.
- NO emojis.
- NO sycophantic openers ("Great", "Got it", "Perfect", "Excellent").
- NO "I understand", "Absolutely", "Of course", "happy to help".
- NO hedging like "could potentially", "might possibly". Be direct.
- NO triple-clause "A, B, and C" sentences. Two clauses max.
- NO exclamation points except extremely rare cases.
- Specific names, specific numbers, specific dollar amounts. Never vague.

# SECTION CONTRACT (output strict JSON matching this schema)

{
  "reflective_summary": "<1 paragraph, 80-120 words. Mirror back their situation. Reference their actual company, role, work_description, and the named pain.>",
  "map_60_25_15": {
    "agent": ["<3-5 bullets>"], "augmented": ["<3-5 bullets>"], "human": ["<3-5 bullets>"]
  },
  "roadmap_axis": "save | gain",
  "roadmap_axis_reason": "<1 sentence>",
  "roadmap_90_day": [
    {"phase": "Days 1-30", "title": "<specific>", "deliverables": ["<bullet>"], "impact": "<costed>"},
    {"phase": "Days 31-60", "title": "<specific>", "deliverables": ["<bullet>"], "impact": "<costed>"},
    {"phase": "Days 61-90", "title": "<specific>", "deliverables": ["<bullet>"], "impact": "<costed>"}
  ],
  "quick_wins": [
    {"title": "<specific>", "effort": "<hours/days>", "owner": "<named role>", "impact": "<costed>"}
  ],
  "costed_gaps": [
    {"precondition": "01 Reliable input | 02 Documentable decision | 03 Narrow scope | 04 Human review", "gap": "<specific>", "cost_of_inaction_monthly": "<$ amount>", "fix": "<one-line>"}
  ],
  "engagement_fit": {
    "recommendation": "Lead Magnet System | Content Engine | Fractional AI Partner Essential | Fractional AI Partner Standard | Fractional AI Partner Investor | Not yet, here is what to build first",
    "price_label": "<e.g. $3.5K/mo>",
    "reason": "<2-3 sentences>"
  },
  "pace_to_absorption_note": "<1 paragraph, ~80 words>"
}

# ANTI-AI-SLOP RULES
- Every claim ties to specific intake answer.
- Numbers > adjectives.
- Named owners > vague "someone".

Return ONLY the JSON object. First char {. Last char }.`;

const userPrompt = `# INTAKE ANSWERS

Buyer: ${paid.name || '(no name)'} <${paid.email}>

${Object.entries(answers).map(([k, v]) => `## ${k}\n${v}`).join('\n\n')}

Generate the Blueprint now. Strict JSON per the schema.`;

const claudeRes = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: { 'x-api-key': secrets.anthropic_key, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
  body: {
    model: 'claude-sonnet-4-6',
    max_tokens: 4000,
    system: [{ type: 'text', text: SYSTEM_PROMPT, cache_control: { type: 'ephemeral' } }],
    messages: [{ role: 'user', content: userPrompt }],
  },
  json: true,
});

const rawText = claudeRes?.content?.[0]?.text || '';
const fb = rawText.indexOf('{'); const lb = rawText.lastIndexOf('}');
if (fb < 0 || lb < 0) throw new Error('no JSON in Claude response: ' + rawText.slice(0, 300));
let sections;
try { sections = JSON.parse(rawText.slice(fb, lb + 1)); }
catch (e) { throw new Error('Claude JSON parse failed: ' + e.message); }

// 3. Render HTML
const escape = (s) => String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const stripDashes = (s) => String(s ?? '').replace(/—/g, ', ').replace(/–/g, ', ');
const clean = (s) => escape(stripDashes(s));
const bullets = (arr) => `<ul>${(arr || []).map(x => `<li>${typeof x === 'string' ? clean(x) : clean(JSON.stringify(x))}</li>`).join('')}</ul>`;
const companyName = String(answers.company || '').split(',')[0].trim() || 'Your company';

const html = `<article class="blueprint">
  <header>
    <p class="eyebrow">The Agent-Ready Blueprint</p>
    <h1>${clean(companyName)}</h1>
    <p class="meta">Prepared for ${clean(paid.name || paid.email)} · ${new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}</p>
  </header>
  <section><h2>Where you are</h2><p>${clean(sections.reflective_summary)}</p></section>
  <section>
    <h2>The 60 / 25 / 15 map</h2>
    <div class="map-grid">
      <div><h3>60 · Agent</h3>${bullets(sections.map_60_25_15?.agent)}</div>
      <div><h3>25 · Augmented</h3>${bullets(sections.map_60_25_15?.augmented)}</div>
      <div><h3>15 · Human</h3>${bullets(sections.map_60_25_15?.human)}</div>
    </div>
  </section>
  <section>
    <h2>90-day roadmap</h2>
    <p class="axis-note"><strong>Axis: ${clean(sections.roadmap_axis)}.</strong> ${clean(sections.roadmap_axis_reason)}</p>
    ${(sections.roadmap_90_day || []).map(p => `
      <div class="phase">
        <h3>${clean(p.phase)} · ${clean(p.title)}</h3>
        ${bullets(p.deliverables)}
        <p class="impact"><em>Impact:</em> ${clean(p.impact)}</p>
      </div>
    `).join('')}
  </section>
  <section>
    <h2>Quick wins</h2>
    <table>
      <thead><tr><th>Win</th><th>Effort</th><th>Owner</th><th>Impact</th></tr></thead>
      <tbody>
        ${(sections.quick_wins || []).filter(w => typeof w === 'object').map(w => `
          <tr><td>${clean(w.title)}</td><td>${clean(w.effort)}</td><td>${clean(w.owner)}</td><td>${clean(w.impact)}</td></tr>
        `).join('')}
      </tbody>
    </table>
  </section>
  <section>
    <h2>Costed gaps</h2>
    <table>
      <thead><tr><th>Precondition</th><th>Gap</th><th>Cost of inaction (monthly)</th><th>Fix</th></tr></thead>
      <tbody>
        ${(sections.costed_gaps || []).map(g => `
          <tr><td>${clean(g.precondition)}</td><td>${clean(g.gap)}</td><td>${clean(g.cost_of_inaction_monthly)}</td><td>${clean(g.fix)}</td></tr>
        `).join('')}
      </tbody>
    </table>
  </section>
  <section class="fit">
    <h2>Engagement fit</h2>
    <p class="recommendation"><strong>${clean(sections.engagement_fit?.recommendation)}</strong> · ${clean(sections.engagement_fit?.price_label)}</p>
    <p>${clean(sections.engagement_fit?.reason)}</p>
  </section>
  <section class="pace"><h2>How we work together</h2><p>${clean(sections.pace_to_absorption_note)}</p></section>
  <footer><p>Agent-Ready Ops™ · Ivan Manfredi · <a href="https://ivanmanfredi.com">ivanmanfredi.com</a></p></footer>
</article>`;

// 4. Insert blueprint
const kind = sessionId.startsWith('cs_test_') ? 'test' : 'real';
const fit = sections.engagement_fit?.recommendation || '(unknown)';

const insertRes = await this.helpers.httpRequest({
  method: 'POST',
  url: `${SUPABASE_URL}/rest/v1/blueprints`,
  headers: { ...sb, Prefer: 'return=representation' },
  body: {
    stripe_session_id: sessionId,
    status: 'draft',
    kind,
    html,
    json_sections: sections,
    embedding_text: `${companyName} | ${answers.work_description || ''} | ${fit}`,
    generation_metadata: {
      model: 'claude-sonnet-4-6',
      input_tokens: claudeRes?.usage?.input_tokens,
      output_tokens: claudeRes?.usage?.output_tokens,
      generated_at: new Date().toISOString(),
    },
  },
  json: true,
});
const inserted = Array.isArray(insertRes) ? insertRes[0] : insertRes;

// 5. Notify Ivan (fire-and-forget; failures don't break flow)
const editorUrl = `https://ivanmanfredi.com/dashboard/blueprints/${encodeURIComponent(sessionId)}`;
const notifText = `Blueprint draft ready for ${companyName}.\n\nFit: ${fit}\n\nReview + edit: ${editorUrl}`;

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://24.199.118.135:8080/message/sendText/ivan-wa',
    headers: { 'Content-Type': 'application/json', apikey: 'evo_ivan_n8nclaw_2026' },
    body: { number: '5491159385939', text: notifText, options: { delay: 1000 } },
    json: true,
  });
} catch (e) { console.error('whatsapp:', e.message); }

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.resend.com/emails',
    headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${secrets.resend_key}` },
    body: {
      from: secrets.resend_from,
      to: ['im@ivanmanfredi.com'],
      subject: `Blueprint draft: ${companyName}`,
      text: notifText,
      html: `<p>Blueprint draft ready for <strong>${escape(companyName)}</strong>.</p><p>Recommended fit: <strong>${escape(fit)}</strong></p><p><a href="${editorUrl}" style="color:#2A8F65;font-weight:600">Review + edit in dashboard →</a></p>`,
      tags: [{ name: 'type', value: 'blueprint_draft_ready' }],
    },
    json: true,
  });
} catch (e) { console.error('email:', e.message); }

return [{ json: { ok: true, blueprint_id: inserted?.id, session_id: sessionId, kind, editor_url: editorUrl, fit } }];
